      "1e97aab5-0ce0-47c7-baed-bab4e1544a5a": {
        "message": {
          "author": "Aurora",
          "model": "gpt-4o",
          "create_time": "24.12.10-08:25.Tue::1733851550"
        },
        "parent": "aaa2396b-b506-4aa5-b77a-ce4105d0f2e9",
